import{_ as e,o as s,c as i,ag as o}from"./chunks/framework.6MCaaFDc.js";const h=JSON.parse('{"title":"Website Design","description":"","frontmatter":{},"headers":[],"relativePath":"theory/internet/website-design.md","filePath":"theory/internet/website-design.md"}'),r={name:"theory/internet/website-design.md"};function n(a,t,d,l,c,g){return s(),i("div",null,[...t[0]||(t[0]=[o('<h1 id="website-design" tabindex="-1">Website Design <a class="header-anchor" href="#website-design" aria-label="Permalink to &quot;Website Design&quot;">​</a></h1><p>A website that looks beautiful but confuses visitors has failed at its job. Good web design is about more than aesthetics — it&#39;s about making sure users can find what they need quickly, on any device, in any condition.</p><div class="note custom-block github-alert"><p class="custom-block-title">Grade 10–11</p><p>Website design principles and evaluation are Grade 10–11 content. Grade 12 extends with scripting, backend technologies, and web standards.</p></div><hr><h2 id="principles-of-good-website-design" tabindex="-1">Principles of Good Website Design <a class="header-anchor" href="#principles-of-good-website-design" aria-label="Permalink to &quot;Principles of Good Website Design&quot;">​</a></h2><h3 id="_1-layout-and-structure" tabindex="-1">1. Layout and Structure <a class="header-anchor" href="#_1-layout-and-structure" aria-label="Permalink to &quot;1. Layout and Structure&quot;">​</a></h3><ul><li><strong>Clear visual hierarchy</strong> — headings, subheadings, body text at distinct sizes</li><li><strong>Consistent layout</strong> — same navigation position on every page</li><li><strong>White space</strong> — breathing room between elements reduces cognitive load</li><li><strong>Grid system</strong> — content aligned to a consistent grid</li></ul><h3 id="_2-navigation" tabindex="-1">2. Navigation <a class="header-anchor" href="#_2-navigation" aria-label="Permalink to &quot;2. Navigation&quot;">​</a></h3><ul><li><strong>Intuitive navigation</strong> — users should find what they need without thinking</li><li><strong>Persistent navigation bar</strong> — always visible, same position</li><li><strong>Breadcrumbs</strong> — show current position (Home &gt; Theory &gt; Networks &gt; Topologies)</li><li><strong>Search function</strong> — for large sites</li><li><strong>3-click rule</strong> — users should reach any page in 3 clicks or fewer</li></ul><h3 id="_3-content" tabindex="-1">3. Content <a class="header-anchor" href="#_3-content" aria-label="Permalink to &quot;3. Content&quot;">​</a></h3><ul><li><strong>Relevant and accurate</strong> — current, correct information</li><li><strong>Concise</strong> — web users scan, not read — short paragraphs, bullet points</li><li><strong>Readable</strong> — sufficient font size (min 16px), high contrast</li><li><strong>Clear headings</strong> — users scan headings to find relevant sections</li><li><strong>No broken links</strong> — regular maintenance required</li></ul><h3 id="_4-visual-design" tabindex="-1">4. Visual Design <a class="header-anchor" href="#_4-visual-design" aria-label="Permalink to &quot;4. Visual Design&quot;">​</a></h3><ul><li><strong>Consistent colour scheme</strong> — limited palette (3–4 colours)</li><li><strong>Font consistency</strong> — max 2–3 font families</li><li><strong>High contrast</strong> — text must contrast clearly with background (WCAG standard: 4.5:1 ratio)</li><li><strong>Quality images</strong> — optimised (compressed) for fast loading</li><li><strong>Brand consistency</strong> — colours, fonts, tone match the organisation</li></ul><h3 id="_5-performance" tabindex="-1">5. Performance <a class="header-anchor" href="#_5-performance" aria-label="Permalink to &quot;5. Performance&quot;">​</a></h3><ul><li><strong>Fast loading</strong> — compress images, minimise CSS/JS files</li><li><strong>Minimal HTTP requests</strong> — combine files where possible</li><li><strong>Content Delivery Network (CDN)</strong> — serve static files from servers near the user</li></ul><h3 id="_6-accessibility" tabindex="-1">6. Accessibility <a class="header-anchor" href="#_6-accessibility" aria-label="Permalink to &quot;6. Accessibility&quot;">​</a></h3><ul><li><strong>Alt text on all images</strong> — for screen readers and when images fail to load</li><li><strong>Keyboard navigation</strong> — all functionality accessible without a mouse</li><li><strong>Captions on videos</strong> — for deaf/hard-of-hearing users</li><li><strong>Sufficient colour contrast</strong> — for colour-blind users</li><li><strong>Responsive design</strong> — works on all screen sizes</li></ul><h3 id="_7-responsiveness" tabindex="-1">7. Responsiveness <a class="header-anchor" href="#_7-responsiveness" aria-label="Permalink to &quot;7. Responsiveness&quot;">​</a></h3><ul><li><strong>Responsive design</strong> — layout adapts to screen size (desktop, tablet, phone)</li><li>Uses CSS media queries to adjust layout</li><li>Images scale proportionally</li><li>Navigation collapses to &quot;hamburger menu&quot; on small screens</li></ul><hr><h2 id="website-evaluation-criteria-accpo" tabindex="-1">Website Evaluation Criteria (ACCPO) <a class="header-anchor" href="#website-evaluation-criteria-accpo" aria-label="Permalink to &quot;Website Evaluation Criteria (ACCPO)&quot;">​</a></h2><p>When evaluating a website&#39;s credibility and quality:</p><table tabindex="0"><thead><tr><th>Criterion</th><th>Questions to ask</th></tr></thead><tbody><tr><td><strong>Authority</strong></td><td>Who created this? Are they qualified? Is there an &quot;About&quot; page? Is the author named?</td></tr><tr><td><strong>Accuracy</strong></td><td>Is the information correct? Are sources cited? Can you verify facts elsewhere?</td></tr><tr><td><strong>Currency</strong></td><td>When was it last updated? Is the information still relevant? Are dates shown?</td></tr><tr><td><strong>Purpose</strong></td><td>Why was it created? To inform, sell, persuade, or entertain? Is there bias?</td></tr><tr><td><strong>Objectivity</strong></td><td>Is information presented fairly? Are multiple viewpoints shown? Any obvious bias?</td></tr></tbody></table><div class="tip custom-block github-alert"><p class="custom-block-title">Quick evaluation check</p><p>Check the URL: <code>.gov</code> = government; <code>.ac</code> or <code>.edu</code> = education; <code>.org</code> = organisation — generally more credible than <code>.com</code> for factual information</p></div><hr><h2 id="w3c-—-world-wide-web-consortium" tabindex="-1">W3C — World Wide Web Consortium <a class="header-anchor" href="#w3c-—-world-wide-web-consortium" aria-label="Permalink to &quot;W3C — World Wide Web Consortium&quot;">​</a></h2><p><strong>W3C</strong> is the international standards organisation for the web, founded by Tim Berners-Lee.</p><p><strong>What W3C does:</strong></p><ul><li>Sets standards for HTML, CSS, accessibility, and web technologies</li><li>Publishes guidelines including: <ul><li><strong>WCAG</strong> (Web Content Accessibility Guidelines)</li><li><strong>HTML5</strong> and <strong>CSS3</strong> specifications</li><li>Web semantics standards</li></ul></li></ul><p><strong>Why follow W3C standards:</strong></p><ul><li>Ensures cross-browser compatibility</li><li>Improves accessibility</li><li>Better SEO (search engines reward standards-compliant sites)</li></ul><hr><h2 id="types-of-websites" tabindex="-1">Types of Websites <a class="header-anchor" href="#types-of-websites" aria-label="Permalink to &quot;Types of Websites&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>Purpose</th><th>Examples</th></tr></thead><tbody><tr><td><strong>Informational</strong></td><td>Provide information</td><td>News sites, encyclopedias, tutorials</td></tr><tr><td><strong>E-commerce</strong></td><td>Sell products/services online</td><td>Takealot, Amazon, Woolworths</td></tr><tr><td><strong>Educational</strong></td><td>Learning resources</td><td>Khan Academy, this site</td></tr><tr><td><strong>Entertainment</strong></td><td>Media, games, social</td><td>YouTube, Netflix, Instagram</td></tr><tr><td><strong>Portfolio</strong></td><td>Showcase work</td><td>Designer/photographer websites</td></tr><tr><td><strong>Corporate</strong></td><td>Company information</td><td>Company homepage, investor relations</td></tr><tr><td><strong>Government</strong></td><td>Public services and information</td><td>SARS, Home Affairs</td></tr><tr><td><strong>Blog</strong></td><td>Regular content publishing</td><td>Personal blogs, journalism</td></tr></tbody></table><hr><h2 id="web-design-technologies" tabindex="-1">Web Design Technologies <a class="header-anchor" href="#web-design-technologies" aria-label="Permalink to &quot;Web Design Technologies&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Technology</th><th>Role</th></tr></thead><tbody><tr><td><strong>HTML</strong></td><td>Structure and content — headings, paragraphs, links, images</td></tr><tr><td><strong>CSS</strong></td><td>Presentation — colours, fonts, layout, spacing</td></tr><tr><td><strong>JavaScript</strong></td><td>Interactivity — button clicks, form validation, dynamic content</td></tr><tr><td><strong>PHP</strong></td><td>Server-side scripting — generates dynamic content from database</td></tr><tr><td><strong>MySQL / SQL</strong></td><td>Database storing dynamic content</td></tr><tr><td><strong>CMS</strong></td><td>Content Management System — allows non-technical editing (WordPress, Joomla)</td></tr></tbody></table><hr><h2 id="user-experience-ux-vs-user-interface-ui" tabindex="-1">User Experience (UX) vs User Interface (UI) <a class="header-anchor" href="#user-experience-ux-vs-user-interface-ui" aria-label="Permalink to &quot;User Experience (UX) vs User Interface (UI)&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>User Interface (UI)</th><th>User Experience (UX)</th></tr></thead><tbody><tr><td>What</td><td>Visual design — what it looks like</td><td>Overall experience — how it feels to use</td></tr><tr><td>Focus</td><td>Aesthetics, layout, colour, typography</td><td>Ease of use, user journey, satisfaction</td></tr><tr><td>Example</td><td>Button colour and size</td><td>Whether the button was easy to find and use</td></tr></tbody></table><p>Good design needs both: beautiful (UI) AND functional (UX).</p><hr><h2 id="common-website-design-mistakes" tabindex="-1">Common Website Design Mistakes <a class="header-anchor" href="#common-website-design-mistakes" aria-label="Permalink to &quot;Common Website Design Mistakes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mistake</th><th>Problem</th></tr></thead><tbody><tr><td>Too many colours/fonts</td><td>Looks unprofessional, confusing</td></tr><tr><td>Slow loading images</td><td>Users leave if page takes &gt; 3 seconds</td></tr><tr><td>No mobile optimisation</td><td>~60% of web traffic is mobile</td></tr><tr><td>Broken links</td><td>Frustrates users; harms SEO</td></tr><tr><td>Too much text on one page</td><td>Users don&#39;t read walls of text</td></tr><tr><td>Auto-playing audio/video</td><td>Annoying — users close immediately</td></tr><tr><td>No search function (large sites)</td><td>Users can&#39;t find content</td></tr><tr><td>Inaccessible content</td><td>Excludes users with disabilities</td></tr></tbody></table><hr><h2 id="key-terms" tabindex="-1">Key Terms <a class="header-anchor" href="#key-terms" aria-label="Permalink to &quot;Key Terms&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th></tr></thead><tbody><tr><td><strong>Responsive design</strong></td><td>Layout adapts to different screen sizes</td></tr><tr><td><strong>Navigation</strong></td><td>System allowing users to move between pages</td></tr><tr><td><strong>Accessibility</strong></td><td>Design usable by people with disabilities</td></tr><tr><td><strong>W3C</strong></td><td>World Wide Web Consortium — web standards organisation</td></tr><tr><td><strong>WCAG</strong></td><td>Web Content Accessibility Guidelines</td></tr><tr><td><strong>3-click rule</strong></td><td>Users should reach any page within 3 clicks</td></tr><tr><td><strong>White space</strong></td><td>Empty space that improves readability and visual clarity</td></tr><tr><td><strong>Breadcrumbs</strong></td><td>Navigation trail showing current page location</td></tr><tr><td><strong>CMS</strong></td><td>Content Management System — enables non-technical editing</td></tr><tr><td><strong>CDN</strong></td><td>Content Delivery Network — serves files from nearby servers</td></tr><tr><td><strong>UI</strong></td><td>User Interface — visual design of a site</td></tr><tr><td><strong>UX</strong></td><td>User Experience — overall experience of using a site</td></tr></tbody></table><hr><h2 id="exam-focus" tabindex="-1">Exam Focus <a class="header-anchor" href="#exam-focus" aria-label="Permalink to &quot;Exam Focus&quot;">​</a></h2><div class="important custom-block github-alert"><p class="custom-block-title">High-Frequency Questions</p><p></p><ol><li><p><strong>&quot;Give FOUR characteristics of a well-designed website&quot;</strong> — consistent navigation; fast loading; responsive (mobile-friendly); high contrast text; accurate and current content; accessibility</p></li><li><p><strong>&quot;Explain the ACCPO criteria for evaluating a website&quot;</strong> — Authority (who created it?); Accuracy (is it correct?); Currency (when updated?); Purpose (why created?); Objectivity (is it biased?)</p></li><li><p><strong>&quot;What is responsive web design?&quot;</strong> — Design that automatically adapts the layout to different screen sizes (desktop, tablet, phone) so the site is usable on any device</p></li><li><p><strong>&quot;What is the role of W3C?&quot;</strong> — International organisation that sets web standards (HTML, CSS, accessibility guidelines) to ensure compatibility and accessibility across browsers</p></li><li><p><strong>&quot;Give TWO accessibility features a website should include&quot;</strong> — alt text on images; captions on videos; keyboard navigation; sufficient colour contrast; screen reader compatibility</p></li></ol></div>',50)])])}const b=e(r,[["render",n]]);export{h as __pageData,b as default};
